                message.textContent = 'Game Over! The word was: ' + secretWord;
                message.className = 'message error';
                gameOver = true;
                gamesLost++;
                streak = 0;
                saveStats();
                document.getElementById('guessInput').disabled = true;
                document.getElementById('submitBtn').style.display = 'none';
